@using sv_ccd7efa3a0d5466fbe83034bfbd594ab.Services
@inject ISettingsService SettingsService

<div class="notifications-section">
    @if (_loading)
    {
        <div class="text-center py-5">
            <div class="spinner-border text-primary" role="status">
                <span class="visually-hidden">Loading...</span>
            </div>
        </div>
    }
    else
    {
        <h4 class="section-heading">Notifications</h4>

        @if (!string.IsNullOrEmpty(_message))
        {
            <div class="alert @(_isError ? "alert-danger" : "alert-success") alert-dismissible fade show" role="alert">
                @_message
                <button type="button" class="btn-close" @onclick="() => _message = null"></button>
            </div>
        }

        <div class="toggle-group mb-4">
            <div class="form-check form-switch mb-3">
                <input class="form-check-input" type="checkbox" role="switch" id="emailNotif" @bind="_emailNotifications" />
                <label class="form-check-label" for="emailNotif">
                    <strong>Email Notifications</strong>
                    <small class="d-block text-muted">Receive notifications via email</small>
                </label>
            </div>

            <div class="form-check form-switch mb-3">
                <input class="form-check-input" type="checkbox" role="switch" id="pushNotif" @bind="_pushNotifications" />
                <label class="form-check-label" for="pushNotif">
                    <strong>Push Notifications</strong>
                    <small class="d-block text-muted">Receive browser push notifications</small>
                </label>
            </div>

            <div class="form-check form-switch mb-3">
                <input class="form-check-input" type="checkbox" role="switch" id="weeklyDigest" @bind="_weeklyDigest" />
                <label class="form-check-label" for="weeklyDigest">
                    <strong>Weekly Digest</strong>
                    <small class="d-block text-muted">Get a weekly summary of activity</small>
                </label>
            </div>
        </div>

        <h5 class="mb-3">Muted Channels</h5>
        <div class="channels-list mb-4">
            @foreach (var channel in _channels)
            {
                <div class="form-check mb-2">
                    <input class="form-check-input" type="checkbox" id="@($"ch-{channel.Name}")"
                           checked="@channel.Muted"
                           @onchange="(e) => ToggleChannel(channel.Name, (bool)(e.Value ?? false))" />
                    <label class="form-check-label" for="@($"ch-{channel.Name}")">
                        #@channel.Name
                    </label>
                </div>
            }
        </div>

        <button class="btn btn-primary" @onclick="SaveAsync" disabled="@_saving">
            @if (_saving)
            {
                <span class="spinner-border spinner-border-sm me-1" role="status"></span>
            }
            Save Preferences
        </button>
    }
</div>

@code {
    private bool _emailNotifications;
    private bool _pushNotifications;
    private bool _weeklyDigest;
    private List<ChannelState> _channels = [];

    private bool _loading = true;
    private bool _saving;
    private string? _message;
    private bool _isError;

    private static readonly string[] AllChannels = ["general", "announcements", "engineering", "marketing", "support", "random"];

    protected override async Task OnInitializedAsync()
    {
        var prefs = await SettingsService.GetNotificationPrefsAsync();
        _emailNotifications = prefs.EmailNotifications;
        _pushNotifications = prefs.PushNotifications;
        _weeklyDigest = prefs.WeeklyDigest;
        _channels = AllChannels.Select(c => new ChannelState(c, prefs.MutedChannels.Contains(c))).ToList();
        _loading = false;
    }

    private void ToggleChannel(string name, bool muted)
    {
        var ch = _channels.FirstOrDefault(c => c.Name == name);
        if (ch is not null)
            ch.Muted = muted;
    }

    private async Task SaveAsync()
    {
        _saving = true;
        _message = null;
        try
        {
            var mutedChannels = _channels.Where(c => c.Muted).Select(c => c.Name).ToList();
            var prefs = new NotificationPrefs(_emailNotifications, _pushNotifications, _weeklyDigest, mutedChannels);
            await SettingsService.SaveNotificationPrefsAsync(prefs);
            _message = "Notification preferences saved!";
            _isError = false;
        }
        catch (Exception ex)
        {
            _message = $"Failed to save: {ex.Message}";
            _isError = true;
        }
        finally
        {
            _saving = false;
        }
    }

    private class ChannelState(string name, bool muted)
    {
        public string Name { get; } = name;
        public bool Muted { get; set; } = muted;
    }
}

