@* Expandable password change panel *@

<div class="change-password-panel">
    <button class="btn btn-outline-secondary w-100 text-start d-flex justify-content-between align-items-center"
            @onclick="() => _expanded = !_expanded">
        <span>🔑 Change Password</span>
        <span class="expand-icon">@(_expanded ? "▲" : "▼")</span>
    </button>

    @if (_expanded)
    {
        <div class="password-form mt-3 p-3">
            @if (!string.IsNullOrEmpty(_message))
            {
                <div class="alert @(_isError ? "alert-danger" : "alert-success") alert-dismissible fade show" role="alert">
                    @_message
                    <button type="button" class="btn-close" @onclick="() => _message = null"></button>
                </div>
            }

            <div class="mb-3">
                <label class="form-label">Current Password</label>
                <input type="password" class="form-control" @bind="_currentPassword" />
            </div>

            <div class="mb-3">
                <label class="form-label">New Password</label>
                <input type="password" class="form-control" @bind="_newPassword" />
            </div>

            <div class="mb-3">
                <label class="form-label">Confirm New Password</label>
                <input type="password" class="form-control" @bind="_confirmPassword" />
            </div>

            <button class="btn btn-warning" @onclick="UpdatePasswordAsync" disabled="@_saving">
                @if (_saving)
                {
                    <span class="spinner-border spinner-border-sm me-1" role="status"></span>
                }
                Update Password
            </button>
        </div>
    }
</div>

@code {
    [Parameter] public EventCallback OnPasswordChanged { get; set; }
    [Parameter] public EventCallback<string> OnChangePassword { get; set; }

    private bool _expanded;
    private string _currentPassword = "";
    private string _newPassword = "";
    private string _confirmPassword = "";
    private bool _saving;
    private string? _message;
    private bool _isError;

    private async Task UpdatePasswordAsync()
    {
        _message = null;

        if (string.IsNullOrWhiteSpace(_currentPassword))
        {
            _message = "Current password is required.";
            _isError = true;
            return;
        }

        if (string.IsNullOrWhiteSpace(_newPassword) || _newPassword.Length < 6)
        {
            _message = "New password must be at least 6 characters.";
            _isError = true;
            return;
        }

        if (_newPassword != _confirmPassword)
        {
            _message = "New passwords do not match.";
            _isError = true;
            return;
        }

        _saving = true;
        try
        {
            await OnChangePassword.InvokeAsync(_currentPassword + "|" + _newPassword);
            _message = "Password updated successfully!";
            _isError = false;
            _currentPassword = "";
            _newPassword = "";
            _confirmPassword = "";
            await OnPasswordChanged.InvokeAsync();
        }
        catch (Exception ex)
        {
            _message = $"Failed to update password: {ex.Message}";
            _isError = true;
        }
        finally
        {
            _saving = false;
        }
    }
}

::deep .password-form {
    background: #f8f9fa;
    border-radius: 0.5rem;
    border: 1px solid #dee2e6;
}

::deep .expand-icon {
    font-size: 0.75rem;
}

@using sv_ccd7efa3a0d5466fbe83034bfbd594ab.Services

<div class="sessions-table">
    <h5 class="mb-3">Active Sessions</h5>
    @if (Sessions is null || Sessions.Count == 0)
    {
        <p class="text-muted">No active sessions.</p>
    }
    else
    {
        <div class="table-responsive">
            <table class="table table-hover align-middle">
                <thead class="table-light">
                    <tr>
                        <th>Device</th>
                        <th>Location</th>
                        <th>Last Active</th>
                        <th></th>
                    </tr>
                </thead>
                <tbody>
                    @foreach (var session in Sessions)
                    {
                        <tr>
                            <td>@session.Device</td>
                            <td>@session.Location</td>
                            <td>@FormatLastActive(session.LastActive)</td>
                            <td>
                                @if (session.Id != CurrentSessionId)
                                {
                                    <button class="btn btn-sm btn-outline-danger"
                                            @onclick="() => OnRevokeRequested.InvokeAsync(session)">
                                        Revoke
                                    </button>
                                }
                                else
                                {
                                    <span class="badge bg-success">Current</span>
                                }
                            </td>
                        </tr>
                    }
                </tbody>
            </table>
        </div>
    }
</div>

@code {
    [Parameter] public List<ActiveSession> Sessions { get; set; } = [];
    [Parameter] public string CurrentSessionId { get; set; } = "sess-1";
    [Parameter] public EventCallback<ActiveSession> OnRevokeRequested { get; set; }

    private static string FormatLastActive(DateTime lastActive)
    {
        var diff = DateTime.UtcNow - lastActive;
        if (diff.TotalMinutes < 1) return "Just now";
        if (diff.TotalMinutes < 60) return $"{(int)diff.TotalMinutes}m ago";
        if (diff.TotalHours < 24) return $"{(int)diff.TotalHours}h ago";
        return $"{(int)diff.TotalDays}d ago";
    }
}

@using sv_ccd7efa3a0d5466fbe83034bfbd594ab.Services

@* Modal confirmation dialog for revoking a session *@

@if (Visible)
{
    <div class="modal-backdrop fade show"></div>
    <div class="modal fade show d-block" tabindex="-1" role="dialog">
        <div class="modal-dialog modal-dialog-centered" role="document">
            <div class="modal-content">
                <div class="modal-header">
                    <h5 class="modal-title">Revoke Session</h5>
                    <button type="button" class="btn-close" @onclick="Cancel"></button>
                </div>
                <div class="modal-body">
                    @if (Session is not null)
                    {
                        <p>Are you sure you want to revoke this session?</p>
                        <div class="session-details p-3 bg-light rounded">
                            <div><strong>Device:</strong> @Session.Device</div>
                            <div><strong>Location:</strong> @Session.Location</div>
                        </div>
                        <p class="mt-3 text-muted small">This will immediately sign out the device.</p>
                    }
                </div>
                <div class="modal-footer">
                    <button type="button" class="btn btn-secondary" @onclick="Cancel">Cancel</button>
                    <button type="button" class="btn btn-danger" @onclick="Confirm">Revoke Session</button>
                </div>
            </div>
        </div>
    </div>
}

@code {
    [Parameter] public bool Visible { get; set; }
    [Parameter] public ActiveSession? Session { get; set; }
    [Parameter] public EventCallback OnConfirm { get; set; }
    [Parameter] public EventCallback OnCancel { get; set; }

    private async Task Confirm() => await OnConfirm.InvokeAsync();
    private async Task Cancel() => await OnCancel.InvokeAsync();
}

@using sv_ccd7efa3a0d5466fbe83034bfbd594ab.Services
@inject ISettingsService SettingsService

<div class="security-section">
    @if (_loading)
    {
        <div class="text-center py-5">
            <div class="spinner-border text-primary" role="status">
                <span class="visually-hidden">Loading...</span>
            </div>
        </div>
    }
    else
    {
        <h4 class="section-heading">Security</h4>

        @if (!string.IsNullOrEmpty(_message))
        {
            <div class="alert @(_isError ? "alert-danger" : "alert-success") alert-dismissible fade show" role="alert">
                @_message
                <button type="button" class="btn-close" @onclick="() => _message = null"></button>
            </div>
        }

        <div class="mb-4">
            <ChangePasswordPanel OnChangePassword="HandleChangePassword" OnPasswordChanged="RefreshData" />
        </div>

        <div class="tfa-section mb-4 p-3">
            <div class="d-flex justify-content-between align-items-center">
                <div>
                    <strong>Two-Factor Authentication</strong>
                    <div class="mt-1">
                        @if (_twoFactorEnabled)
                        {
                            <span class="badge bg-success">Enabled</span>
                        }
                        else
                        {
                            <span class="badge bg-warning text-dark">Disabled</span>
                        }
                    </div>
                </div>
                <div class="form-check form-switch">
                    <input class="form-check-input" type="checkbox" role="switch" id="tfaSwitch"
                           @bind="_twoFactorEnabled" />
                </div>
            </div>
            @if (_lastPasswordChange.HasValue)
            {
                <small class="text-muted d-block mt-2">
                    Last password change: @_lastPasswordChange.Value.ToString("MMM dd, yyyy")
                </small>
            }
        </div>

        <ActiveSessionsTable Sessions="_sessions"
                             CurrentSessionId="sess-1"
                             OnRevokeRequested="ShowRevokeDialog" />

        <RevokeSessionDialog Visible="_showRevokeDialog"
                             Session="_sessionToRevoke"
                             OnConfirm="ConfirmRevoke"
                             OnCancel="CancelRevoke" />
    }
</div>

@code {
    private bool _loading = true;
    private bool _twoFactorEnabled;
    private DateTime? _lastPasswordChange;
    private List<ActiveSession> _sessions = [];
    private string? _message;
    private bool _isError;

    // Revoke dialog state
    private bool _showRevokeDialog;
    private ActiveSession? _sessionToRevoke;

    protected override async Task OnInitializedAsync()
    {
        await LoadDataAsync();
        _loading = false;
    }

    private async Task LoadDataAsync()
    {
        var settings = await SettingsService.GetSecuritySettingsAsync();
        _twoFactorEnabled = settings.TwoFactorEnabled;
        _lastPasswordChange = settings.LastPasswordChange;
        _sessions = settings.Sessions.ToList();
    }

    private async Task HandleChangePassword(string passwordData)
    {
        var parts = passwordData.Split('|', 2);
        await SettingsService.ChangePasswordAsync(parts[0], parts[1]);
    }

    private async Task RefreshData()
    {
        await LoadDataAsync();
        StateHasChanged();
    }

    private void ShowRevokeDialog(ActiveSession session)
    {
        _sessionToRevoke = session;
        _showRevokeDialog = true;
    }

    private async Task ConfirmRevoke()
    {
        if (_sessionToRevoke is not null)
        {
            try
            {
                await SettingsService.RevokeSessionAsync(_sessionToRevoke.Id);
                _sessions.RemoveAll(s => s.Id == _sessionToRevoke.Id);
                _message = $"Session on {_sessionToRevoke.Device} has been revoked.";
                _isError = false;
            }
            catch (Exception ex)
            {
                _message = $"Failed to revoke session: {ex.Message}";
                _isError = true;
            }
        }
        _showRevokeDialog = false;
        _sessionToRevoke = null;
    }

    private void CancelRevoke()
    {
        _showRevokeDialog = false;
        _sessionToRevoke = null;
    }
}

