    align-items: center;
    padding: var(--preview-padding, 1rem);
    border-bottom: 1px solid rgba(0,0,0,0.1);
}

::deep .preview-badge {
    font-size: 0.75rem;
    padding: 0.2em 0.6em;
    border-radius: 1rem;
    background: rgba(0,0,0,0.1);
}

::deep .preview-content {
    padding: var(--preview-padding, 1rem);
}

::deep .preview-text {
    margin-bottom: 0.75rem;
}

::deep .preview-card {
    border: 1px solid rgba(0,0,0,0.1);
    border-radius: 0.375rem;
    margin-bottom: 0.75rem;
    overflow: hidden;
}

::deep .preview-card-title {
    padding: var(--preview-padding, 0.75rem);
    font-weight: 600;
    border-bottom: 1px solid rgba(0,0,0,0.1);
}

::deep .preview-card-body {
    padding: var(--preview-padding, 0.75rem);
}

::deep .preview-actions {
    display: flex;
    gap: 0.5rem;
}

::deep .preview-btn {
    padding: 0.25rem 0.75rem;
    border-radius: 0.25rem;
    font-size: 0.875em;
    cursor: default;
}

/* Light theme */
::deep .preview-light {
    background: #ffffff;
    color: #212529;
}

::deep .preview-light .preview-header {
    background: #f8f9fa;
}

::deep .preview-light .preview-btn.primary {
    background: #0d6efd;
    color: #fff;
}

::deep .preview-light .preview-btn.secondary {
    background: #6c757d;
    color: #fff;
}

/* Dark theme */
::deep .preview-dark {
    background: #1a1d21;
    color: #e9ecef;
}

::deep .preview-dark .preview-header {
    background: #2b3035;
    border-color: rgba(255,255,255,0.1);
}

::deep .preview-dark .preview-badge {
    background: rgba(255,255,255,0.15);
}

::deep .preview-dark .preview-card {
    border-color: rgba(255,255,255,0.15);
}

::deep .preview-dark .preview-card-title {
    border-color: rgba(255,255,255,0.1);
}

::deep .preview-dark .preview-btn.primary {
    background: #3d8bfd;
    color: #fff;
}

::deep .preview-dark .preview-btn.secondary {
    background: #495057;
    color: #fff;
}

/* System theme — split half and half */
::deep .preview-system {
    background: linear-gradient(135deg, #ffffff 50%, #1a1d21 50%);
    color: #212529;
}

::deep .preview-system .preview-header {
    background: rgba(248,249,250,0.9);
}

::deep .preview-system .preview-btn.primary {
    background: #0d6efd;
    color: #fff;
}

::deep .preview-system .preview-btn.secondary {
    background: #6c757d;
    color: #fff;
}

